<script setup lang="ts">
import { ref } from "vue";
import { apiRequest } from "../../../api";
import { useLocale } from "../../../i18n";
const emit = defineEmits<{ authenticated: [token: string] }>();
const account = ref(""); const password = ref(""); const error = ref(""); const pending = ref(false);
const { locale, t, toggleLocale } = useLocale();
async function submit() { error.value="";pending.value=true;try{const data=await apiRequest<{accessToken:string;refreshToken:string;user:{roles:string[]}}>("/auth/login",{method:"POST",body:JSON.stringify({account:account.value,password:password.value})});if(!data.user.roles.some((role)=>role==="CUSTOMER"||role.startsWith("PLATFORM_")||role.startsWith("MERCHANT_")))throw new Error();sessionStorage.setItem("mc-admin-token",data.accessToken);sessionStorage.setItem("mc-admin-refresh",data.refreshToken);emit("authenticated",data.accessToken);}catch{error.value=t("login.error");}finally{pending.value=false;}}
</script>
<template><main class="login"><div class="art"><div class="brand"><span>M</span><b>MoeCraft</b></div><div class="art-copy"><small>CREATOR COMMERCE</small><h1>{{t('login.heroTitle')}}</h1><p>{{t('login.heroSubtitle')}}</p></div><div class="orbits"><i/><i/><i/><span>MC</span></div><p class="copyright">© 2026 MoeCraft Creator Platform</p></div><section class="form-side"><button class="locale" @click="toggleLocale">{{locale==='zh-CN'?'EN':'中文'}}</button><form @submit.prevent="submit"><span class="eyebrow">WELCOME BACK</span><h2>{{t('login.title')}}</h2><p>{{t('login.subtitle')}}</p><label><span>{{t('login.account')}}</span><input v-model="account" autocomplete="username" required :placeholder="t('login.accountPlaceholder')"/></label><label><span>{{t('login.password')}}</span><input v-model="password" type="password" autocomplete="current-password" required :placeholder="t('login.passwordPlaceholder')"/></label><p v-if="error" class="error" role="alert">{{error}}</p><button class="submit" :disabled="pending">{{pending?t('login.pending'):t('login.submit')}}</button><small class="security">◇ {{t('login.security')}}</small></form></section></main></template>
<style scoped>.login{display:grid;min-height:100dvh;grid-template-columns:minmax(380px,1.1fr) minmax(420px,.9fr);background:var(--surface)}.art{position:relative;display:flex;overflow:hidden;padding:38px 50px;flex-direction:column;background:linear-gradient(145deg,#171535,#292562 65%,#493b8f);color:white}.art::before{position:absolute;inset:0;background:radial-gradient(circle at 76% 28%,rgb(151 126 255 / 28%),transparent 25%),radial-gradient(circle at 20% 80%,rgb(72 192 191 / 14%),transparent 25%);content:""}.brand{position:relative;z-index:1;display:flex;align-items:center;gap:11px}.brand span{display:grid;width:38px;height:38px;place-items:center;border-radius:12px;background:linear-gradient(145deg,#735fec,#b072da);font-weight:700}.art-copy{position:relative;z-index:1;margin:auto 0}.art-copy small{color:#a99cef;font-size:10px;font-weight:700;letter-spacing:.2em}.art-copy h1{margin:17px 0;color:white;font-size:clamp(32px,4vw,57px);line-height:1.22;letter-spacing:-.05em}.art-copy p{color:#aaa7c4}.orbits{position:absolute;width:330px;height:330px;right:-70px;bottom:-75px;border:1px solid rgb(255 255 255 / 10%);border-radius:50%}.orbits i{position:absolute;inset:40px;border:1px solid rgb(255 255 255 / 9%);border-radius:50%}.orbits i:nth-child(2){inset:85px}.orbits i:nth-child(3){inset:130px}.orbits span{position:absolute;display:grid;width:54px;height:54px;left:138px;top:138px;place-items:center;border-radius:17px;background:rgb(255 255 255 / 11%);font-weight:700}.copyright{position:relative;z-index:1;margin:0;color:#8581a2;font-size:10px}.form-side{position:relative;display:grid;padding:40px;place-items:center;background:var(--surface)}.locale{position:absolute;right:35px;top:30px;padding:7px 11px;border:1px solid var(--border);border-radius:8px;background:var(--surface-raised);color:var(--text-secondary);cursor:pointer}.form-side form{display:grid;width:min(100%,390px);gap:17px}.eyebrow{color:#6957e8;font-size:10px;font-weight:700;letter-spacing:.18em}.form-side h2{margin:0;color:var(--text);font-size:30px;letter-spacing:-.035em}.form-side form>p{margin:-8px 0 10px;color:var(--text-muted);font-size:12px;line-height:1.6}.form-side label{display:grid;gap:7px}.form-side label span{color:var(--text-secondary);font-size:11px;font-weight:600}.form-side input{padding:13px 14px;border:1px solid var(--border);outline:0;border-radius:9px;background:var(--surface-raised);color:var(--text)}.form-side input:focus{border-color:#6957e8;background:var(--surface);box-shadow:0 0 0 3px rgb(105 87 232 / 11%)}.submit{min-height:45px;margin-top:4px;border:0;border-radius:10px;background:linear-gradient(135deg,#6957e8,#5542ce);box-shadow:0 10px 24px rgb(105 87 232 / 24%);color:white;font-weight:650;cursor:pointer}.submit:disabled{opacity:.6}.form-side .error{padding:10px 12px;margin:0;border-radius:8px;background:var(--danger-soft);color:var(--danger)}.security{text-align:center;color:var(--text-muted);font-size:9px}@media(max-width:800px){.login{grid-template-columns:1fr}.art{display:none}.form-side{padding:28px}.locale{right:20px;top:20px}}</style>
